#!/usr/bin/env node
/**
 * Drift check: assert WP_TRACEABILITY_REGISTRY.md matches the projection
 * rendered from wp_traceability_registry.json.
 *
 * The .json is authority; the .md is a generated projection regenerated by
 * `wp-traceability-set.mjs` and the migration helper. A hand-edit to the .md
 * (or a script that writes the .md directly without going through the lib)
 * will cause the .md to diverge from the .json. This check catches that drift
 * and tells the operator to re-run the migration helper.
 */

import fs from "node:fs";
import {
  loadRegistryJson,
  renderRegistryMarkdown,
  REGISTRY_DEFAULT_JSON_PATH,
  REGISTRY_DEFAULT_MD_PATH,
} from "../scripts/lib/traceability-registry-lib.mjs";

function fail(message, details = []) {
  console.error(`wp-traceability-registry-projection-check failed: ${message}`);
  for (const detail of details) console.error(`- ${detail}`);
  process.exit(1);
}

function normalizeLf(text) {
  return String(text).replace(/\r\n/g, "\n");
}

if (!fs.existsSync(REGISTRY_DEFAULT_JSON_PATH)) {
  fail(
    `Missing authority JSON: ${REGISTRY_DEFAULT_JSON_PATH}`,
    [
      "Run: node -e \"import('./.GOV/roles_shared/scripts/lib/traceability-registry-lib.mjs').then((m) => m.migrateRegistryFromMarkdownIfNeeded())\"",
    ],
  );
}
if (!fs.existsSync(REGISTRY_DEFAULT_MD_PATH)) {
  fail(`Missing projection: ${REGISTRY_DEFAULT_MD_PATH}`);
}

let registry;
try {
  registry = loadRegistryJson(REGISTRY_DEFAULT_JSON_PATH);
} catch (e) {
  fail(`Failed to load authority JSON`, [String(e?.message || e)]);
}

const expected = normalizeLf(renderRegistryMarkdown(registry));
const actual = normalizeLf(fs.readFileSync(REGISTRY_DEFAULT_MD_PATH, "utf8"));

if (expected !== actual) {
  fail(
    "WP_TRACEABILITY_REGISTRY.md is out of sync with wp_traceability_registry.json",
    [
      "The .md projection must be regenerated from the .json authority.",
      "Re-run wp-traceability-set.mjs for any pending change, or rerun the lib's persistRegistry helper to regenerate the projection in place.",
      "Do not hand-edit WP_TRACEABILITY_REGISTRY.md - it is auto-generated.",
    ],
  );
}

console.log(
  `wp-traceability-registry-projection-check ok: registry .md matches .json (${registry.entries.length} entries, ${registry.superseded_activation_history.length} superseded, ${registry.historical_lineage.length} lineage)`,
);
